<script lang="ts">
    import { createEventDispatcher } from 'svelte';
    import { get } from 'svelte/store';
    import { Constants } from '../Constants';
    import { apiPostWithBackup } from '../utils';
    import { sortedTagFiles, fetchTags } from '../stores/tags';
    import { t } from '../i18n';

    const dispatch = createEventDispatcher<{ done: void }>();

    let dialog: HTMLDialogElement;

    // ---- フォーム状態 ----
    let fileId = '';
    let categoryName = '';

    // ファイルの新規入力切替
    let isNewFile = false;
    let newFileName = '';

    // 編集前の値
    let origFileId = '';
    let origCategoryName = '';

    let errorMsg = '';
    let saving = false;

    // ---- ファイル選択肢 ----
    $: files = $sortedTagFiles;

    // ---- 重複チェック（移動先 / リネーム先に同名カテゴリが既存か） ----
    $: isDuplicate = (() => {
        if (isNewFile) return false;
        const trimmed = categoryName.trim();
        if (!trimmed) return false;
        if (fileId === origFileId && trimmed === origCategoryName) return false;
        const targetFile = files.find((f) => f.fileId === fileId);
        if (!targetFile) return false;
        return targetFile.categories.some((c) => c.categoryId === trimmed);
    })();

    $: effectiveFileId = isNewFile ? newFileName.trim() : fileId;
    $: canSave =
        categoryName.trim() !== '' &&
        effectiveFileId !== '' &&
        !isDuplicate &&
        !saving;

    // ---- 公開メソッド ----
    export function openEdit(fId: string, catId: string) {
        fileId = fId;
        categoryName = catId;
        origFileId = fId;
        origCategoryName = catId;
        isNewFile = false;
        newFileName = '';
        errorMsg = '';
        saving = false;
        dialog.showModal();
    }

    // ---- 保存 ----
    async function handleSave() {
        if (!canSave) return;
        saving = true;
        errorMsg = '';
        try {
            await apiPostWithBackup('/edit_category', {
                file: origFileId,
                category: origCategoryName,
                new_file: isNewFile ? '__new__' : fileId,
                new_file_name: isNewFile ? newFileName.trim() : null,
                new_category: categoryName.trim(),
            });
            await fetchTags();
            dialog.close();
            dispatch('done');
        } catch (e) {
            errorMsg = get(t)('common.error.generic');
        } finally {
            saving = false;
        }
    }

    function handleCancel() {
        dialog.close();
    }
</script>

<dialog class="d2ps-dialog-root" bind:this={dialog}>
    <div class="d2ps-dialog">
        <h3 class="d2ps-dialog__title">{$t('category.edit.title')}</h3>

        <!-- ファイル（タブ） -->
        <label class="d2ps-dialog__label">
            <span>{$t('category.field.file')}</span>
            <div class="d2ps-dialog__row">
                {#if !isNewFile}
                    <select class="d2ps-dialog__select" bind:value={fileId}>
                        {#each files as f (f.fileId)}
                            <option value={f.fileId}>{f.fileId}</option>
                        {/each}
                    </select>
                    <button
                        class="{Constants.CSS_CLASS_BUTTON_BASE} {Constants.CSS_CLSSS_BUTTON_PRIMARY} d2ps-dialog__new-btn"
                        on:click={() => {
                            isNewFile = true;
                            newFileName = '';
                        }}>{$t('common.new')}</button
                    >
                {:else}
                    <input
                        class="d2ps-dialog__input"
                        type="text"
                        placeholder={$t('category.field.newFileName')}
                        bind:value={newFileName}
                    />
                    <button
                        class="{Constants.CSS_CLASS_BUTTON_BASE} {Constants.CSS_CLSSS_BUTTON_PRIMARY} d2ps-dialog__new-btn"
                        on:click={() => {
                            isNewFile = false;
                        }}>{$t('common.existing')}</button
                    >
                {/if}
            </div>
        </label>

        <!-- カテゴリ名 -->
        <label class="d2ps-dialog__label">
            <span>{$t('category.field.name')}</span>
            <input class="d2ps-dialog__input" type="text" bind:value={categoryName} />
        </label>

        <!-- エラー・重複 -->
        {#if isDuplicate}
            <p class="d2ps-dialog__error">{$t('category.error.duplicate')}</p>
        {/if}
        {#if errorMsg}
            <p class="d2ps-dialog__error">{errorMsg}</p>
        {/if}

        <!-- ボタン -->
        <div class="d2ps-dialog__buttons">
            <button
                class="{Constants.CSS_CLASS_BUTTON_BASE} {Constants.CSS_CLSSS_BUTTON_PRIMARY}"
                on:click={handleSave}
                disabled={!canSave}
            >
                {saving ? $t('common.saving') : $t('common.save')}
            </button>
            <button
                class="{Constants.CSS_CLASS_BUTTON_BASE} {Constants.CSS_CLSSS_BUTTON_SECONDARY}"
                on:click={handleCancel}>{$t('common.cancel')}</button
            >
        </div>
    </div>
</dialog>
